SELECT bs."in.comstock_building_type" AS comstock_building_type, count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS sample_count, (count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(1) / CAST(count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS DECIMAL) AS rows_per_sample, sum(ts_pivot."bs__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__baseline", sum(ts_pivot."up__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(ts_pivot."bs__out.electricity.total.energy_consumption", 0) - coalesce(ts_pivot."up__out.electricity.total.energy_consumption", 0)) * bs.weight) AS "electricity.total.energy_consumption__savings", sum(ts_pivot."bs__out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__baseline", sum(ts_pivot."up__out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__upgrade", sum((coalesce(ts_pivot."bs__out.natural_gas.total.energy_consumption", 0) - coalesce(ts_pivot."up__out.natural_gas.total.energy_consumption", 0)) * bs.weight) AS "natural_gas.total.energy_consumption__savings" FROM (SELECT comstock_amy2018_r2_2025_ts_by_state.bldg_id AS bldg_id, comstock_amy2018_r2_2025_ts_by_state.state AS state, comstock_amy2018_r2_2025_ts_by_state.timestamp AS timestamp, sum(CASE WHEN (comstock_amy2018_r2_2025_ts_by_state.upgrade = 0) THEN comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" ELSE NULL END) AS "bs__out.electricity.total.energy_consumption", sum(CASE WHEN (comstock_amy2018_r2_2025_ts_by_state.upgrade = 1) THEN comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" ELSE NULL END) AS "up__out.electricity.total.energy_consumption", sum(CASE WHEN (comstock_amy2018_r2_2025_ts_by_state.upgrade = 0) THEN comstock_amy2018_r2_2025_ts_by_state."out.natural_gas.total.energy_consumption" ELSE NULL END) AS "bs__out.natural_gas.total.energy_consumption", sum(CASE WHEN (comstock_amy2018_r2_2025_ts_by_state.upgrade = 1) THEN comstock_amy2018_r2_2025_ts_by_state."out.natural_gas.total.energy_consumption" ELSE NULL END) AS "up__out.natural_gas.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state WHERE comstock_amy2018_r2_2025_ts_by_state.upgrade IN (0, 1) AND comstock_amy2018_r2_2025_ts_by_state.state IN ('CO', 'NM') AND (comstock_amy2018_r2_2025_ts_by_state.bldg_id, comstock_amy2018_r2_2025_ts_by_state.state) IN (SELECT bs.bldg_id, bs.state FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs WHERE bs.upgrade IN (1, 2) AND bs.applicability = true GROUP BY bs.bldg_id, bs.state HAVING count(distinct(bs.upgrade)) = 2) GROUP BY comstock_amy2018_r2_2025_ts_by_state.bldg_id, comstock_amy2018_r2_2025_ts_by_state.state, comstock_amy2018_r2_2025_ts_by_state.timestamp) AS ts_pivot JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs ON bs.bldg_id = ts_pivot.bldg_id AND bs.state = ts_pivot.state AND bs.upgrade = 0 AND bs.state IN ('CO', 'NM') GROUP BY 1 ORDER BY 1